        database_root / "virus" / "rsv" / "nmdc_hrsv_variation_list_zh.tsv",
        report_dir / "vadr" / f"{sample_name}.vadr.gff3",
        report_dir / f"{sample_name}_virus_typing" / "vadr" / f"{sample_name}.vadr.gff3",
